WITH white_race AS (SELECT "Code" FROM "DEATH"."DEATH"."RACE" WHERE UPPER("Description") LIKE '%WHITE%'), discharge_codes AS (SELECT "Code" FROM "DEATH"."DEATH"."ICD10CODE" WHERE UPPER("Description") LIKE '%DISCHARGE%' AND UPPER("Description") NOT LIKE '%URETHRAL DISCHARGE%' AND UPPER("Description") NOT LIKE '%DISCHARGE OF FIREWORK%' AND UPPER("Description") NOT LIKE '%LEGAL INTERVENTION INVOLVING FIREARM DISCHARGE%'), vehicle_codes AS (SELECT "Code" FROM "DEATH"."DEATH"."ICD10CODE" WHERE UPPER("Description") LIKE '%VEHICLE%'), all_age_groups AS (SELECT DISTINCT "AgeRecode12" FROM "DEATH"."DEATH"."DEATHRECORDS" d INNER JOIN white_race wr ON d."Race" = wr."Code"), discharge_counts AS (SELECT a."AgeRecode12", COUNT(d."Id") AS discharge_count FROM all_age_groups a LEFT JOIN "DEATH"."DEATH"."DEATHRECORDS" d ON a."AgeRecode12" = d."AgeRecode12" INNER JOIN white_race wr ON d."Race" = wr."Code" INNER JOIN discharge_codes dc ON d."Icd10Code" = dc."Code" GROUP BY a."AgeRecode12"), vehicle_counts AS (SELECT a."AgeRecode12", COUNT(d."Id") AS vehicle_count FROM all_age_groups a LEFT JOIN "DEATH"."DEATH"."DEATHRECORDS" d ON a."AgeRecode12" = d."AgeRecode12" INNER JOIN white_race wr ON d."Race" = wr."Code" INNER JOIN vehicle_codes vc ON d."Icd10Code" = vc."Code" GROUP BY a."AgeRecode12") SELECT AVG(dc.discharge_count) - AVG(vc.vehicle_count) AS difference_in_averages FROM discharge_counts dc INNER JOIN vehicle_counts vc ON dc."AgeRecode12" = vc."AgeRecode12"